SELECT [Sales Price Model Item].*
FROM [Sales Price Model Item]
WHERE ((([Sales Price Model Item].[Model Item No_])="7FARIA01/LEA" Or ([Sales Price Model Item].[Model Item No_])="7FWOSUONO01/LEA" Or ([Sales Price Model Item].[Model Item No_])="YLE14/TEXTURED" Or ([Sales Price Model Item].[Model Item No_])="DLY32/NET" Or ([Sales Price Model Item].[Model Item No_])="JNE04/CROSTA-VIT" Or ([Sales Price Model Item].[Model Item No_])="7FMURRAY01/LEA" Or ([Sales Price Model Item].[Model Item No_])="7SWOBOWLING/LEA" Or ([Sales Price Model Item].[Model Item No_])="8SMADISON01/MES" Or ([Sales Price Model Item].[Model Item No_])="8SMASTER01/LEA"));

